@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode
    {
        get
        {
            var endpoint = HttpContext?.GetEndpoint();
            var renderModeAttribute = endpoint?.Metadata.GetMetadata<RenderModeAttribute>();
            // Pages that explicitly declare @attribute [RenderModeInteractiveServer] get that mode.
            // Pages with no render mode attribute default to InteractiveServer (global interactivity).
            // Pages that opt out use a custom attribute to signal static SSR (null render mode).
            if (endpoint?.Metadata.GetMetadata<StaticSsrAttribute>() is not null)
                return null;
            return renderModeAttribute?.Mode ?? InteractiveServer;
        }
    }
}

