namespace BlazorApp;

/// <summary>
/// When applied to a routable page component, signals that the page should be
/// rendered using static server-side rendering (no interactive render mode).
/// This allows the page to access HttpContext directly.
/// </summary>
[AttributeUsage(AttributeTargets.Class)]
public sealed class StaticSsrAttribute : Attribute;

@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [BlazorApp.StaticSsr]

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsentCookie)
{
    <div class="alert alert-success" role="alert">
        ✓ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>How We Use Cookies</h2>
<p>
    This application uses cookies to improve your experience. By using our site,
    you acknowledge that you have read and understand our cookie policy.
</p>

<h2>Data Collection</h2>
<p>
    We collect only the data necessary to provide our services. Your personal
    information is never sold to third parties.
</p>

<h2>Your Rights</h2>
<p>
    You may request deletion of your data at any time by contacting us.
</p>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsentCookie =>
        HttpContext?.Request.Cookies.ContainsKey("consent") == true;
}

